/* Minimal HTMX-compatible library for RAG-Bachelor.
 * Implements: hx-get, hx-post, hx-target, hx-swap (innerHTML/outerHTML),
 *             hx-vals, hx-indicator, hx-encoding, hx-trigger.
 */
(function () {
  "use strict";

  var IND_CLASS = "htmx-request";

  function showInd(sel) {
    if (!sel) return null;
    var el = document.querySelector(sel);
    if (el) el.classList.add(IND_CLASS);
    return el;
  }

  function hideInd(el) {
    if (el) el.classList.remove(IND_CLASS);
  }

  function resolveTarget(el, sel) {
    if (!sel || sel === "this") return el;
    return document.querySelector(sel);
  }

  function doSwap(target, html, swap) {
    if (!target) return;
    if ((swap || "innerHTML") === "outerHTML") {
      var tmp = document.createElement("div");
      tmp.innerHTML = html;
      var nodes = Array.from(tmp.childNodes);
      target.replaceWith.apply(target, nodes);
      nodes.forEach(function (n) { if (n.querySelectorAll) processAll(n); });
    } else {
      target.innerHTML = html;
      processAll(target);
    }
  }

  // Security: innerHTML is used to swap server-supplied HTML fragments.
  // We only accept same-origin responses (enforced below) and Jinja2
  // auto-escaping ensures all user-supplied values in templates are escaped.
  // This app runs on localhost only; never expose it to an untrusted network.
  function fire(method, url, body, encoding, target, swap, indSel) {
    var ind = showInd(indSel);

    // XHR for multipart — fetch + FormData is unreliable for file uploads in Firefox.
    if (encoding === "multipart/form-data") {
      var xhr = new XMLHttpRequest();
      xhr.open(method, url);
      xhr.onload = function () {
        hideInd(ind);
        if (xhr.status >= 200 && xhr.status < 300) {
          doSwap(target, xhr.responseText, swap);
        } else {
          console.error("[htmx] HTTP " + xhr.status, xhr.responseText);
        }
      };
      xhr.onerror = function () { hideInd(ind); console.error("[htmx] XHR network error"); };
      xhr.send(body);
      return;
    }

    var opts = { method: method };
    if (body !== null) {
      opts.headers = { "Content-Type": "application/x-www-form-urlencoded" };
      opts.body = body;
    }
    fetch(url, opts)
      .then(function (r) {
        // Reject cross-origin responses — all our endpoints are same-origin.
        var origin = window.location.origin;
        if (r.url && !r.url.startsWith(origin)) {
          console.error("[htmx] Rejected cross-origin response:", r.url);
          hideInd(ind);
          return "";
        }
        return r.text();
      })
      .then(function (html) { if (html !== "") { hideInd(ind); doSwap(target, html, swap); } })
      .catch(function (e) { hideInd(ind); console.error("[htmx]", e); });
  }

  function bindElement(el) {
    if (el._hx) return;
    var hxPost = el.getAttribute("hx-post");
    var hxGet  = el.getAttribute("hx-get");
    var method = hxPost ? "POST" : hxGet ? "GET" : null;
    if (!method) return;
    el._hx = true;

    var url       = hxPost || hxGet || "";
    var targetSel = el.getAttribute("hx-target");
    var swap      = el.getAttribute("hx-swap")      || "innerHTML";
    var valsRaw   = el.getAttribute("hx-vals")      || null;
    var indSel    = el.getAttribute("hx-indicator") || null;
    var encoding  = el.getAttribute("hx-encoding")  || null;
    var defTrig   = el.tagName === "FORM" ? "submit" : "click";
    var trigger   = el.getAttribute("hx-trigger")   || defTrig;

    el.addEventListener(trigger, function (e) {
      e.preventDefault();
      // hx-confirm: value is a plain text attribute — never injected into JS
      var confirmMsg = el.getAttribute("hx-confirm");
      if (confirmMsg && !window.confirm(confirmMsg)) return;
      var target = resolveTarget(el, targetSel);
      var body   = null;

      if (method === "POST") {
        var extra = {};
        if (valsRaw) {
          try { extra = JSON.parse(valsRaw); } catch (_) {}
        }
        var isMulti = encoding === "multipart/form-data" ||
                      (el.tagName === "FORM" && el.enctype === "multipart/form-data");
        if (el.tagName === "FORM") {
          var fd = new FormData(el);
          Object.keys(extra).forEach(function (k) { fd.append(k, extra[k]); });
          if (isMulti) {
            body = fd;
            encoding = "multipart/form-data";
          } else {
            var p = new URLSearchParams();
            fd.forEach(function (v, k) { p.append(k, v); });
            body = p.toString();
          }
        } else {
          var p2 = new URLSearchParams();
          Object.keys(extra).forEach(function (k) { p2.append(k, extra[k]); });
          body = p2.toString();
        }
      }

      fire(method, url, body, encoding, target, swap, indSel);
    });
  }

  function processAll(root) {
    var els = (root || document).querySelectorAll("[hx-post],[hx-get]");
    els.forEach(bindElement);
  }

  document.addEventListener("DOMContentLoaded", function () { processAll(document); });
  window.htmx = { processAll: processAll };
})();
